function runLoginTest(iteration) {
  cy.visit('http://103.182.234.231:90/login');
  cy.get('input[name="email"]').clear().type(Cypress.env('EMAIL'));
  cy.get('input[name="password"]').clear().type(Cypress.env('PASSWORD'), {
    log: false
  });
  const startTime = Date.now();
  cy.get('button[type="submit"]').click();
  cy.url({
    timeout: 60000
  }).should('not.include', '/login').then(() => {
    const duration = Date.now() - startTime;
    cy.log(`Percobaan ${iteration}: ${duration} ms`);
    expect(duration).to.be.lessThan(MAX_CONSISTENCY_TIME);
  });
}
runLoginTest(1);
cy.clearCookies();
cy.clearLocalStorage();
runLoginTest(2);
cy.clearCookies();
cy.clearLocalStorage();
runLoginTest(3);
